sys_script_include.script:
var TelecomIncidentUtils = Class.create();
TelecomIncidentUtils.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

    /**
     * Fetches the location and category of a given Configuration Item (CI).
     * Called asynchronously from the Client Script to prevent UI freezing.
     * 
     * @returns {string} JSON stringified object containing location and category.
     */

    getNetworkElementDetails: function() {
		// 1. Retrieve the sys_id passed from the Client Script
        var ciId = this.getParameter('sysparm_ci_id');
		// 2. Initialize the payload with default safe values
        var result = {
            location: 'Unknown Location',
            category: 'Unknown Category'
        };
		// 3. Guard Clause: If sys_id is missing, abort DB query and return defaults
        if (!ciId) {
            return JSON.stringify(result);
        }
        var ciGr = new GlideRecord('cmdb_ci');
        if (ciGr.get(ciId)) {
			// Use getDisplayValue() for reference fields to get readable names
            result.location = ciGr.getDisplayValue('location') || 'No Location Assigned';
            result.category = ciGr.getValue('category') || 'No Category Assigned';
        }

        return JSON.stringify(result);
    },
    type: 'TelecomIncidentUtils'
});
